import{_ as e,o as a,c as i,aw as l}from"./chunks/framework.DLufY-ao.js";const r="/workbook/assets/heap.CV3mLBy_.png",g=JSON.parse('{"title":"Heap (Куча)","description":"","frontmatter":{},"headers":[],"relativePath":"wiki/dev-commit/theory/data-structures/structures/heap.md","filePath":"wiki/dev-commit/theory/data-structures/structures/heap.md"}'),s={name:"wiki/dev-commit/theory/data-structures/structures/heap.md"};function d(o,t,n,h,c,u){return a(),i("div",null,[...t[0]||(t[0]=[l('<h1 id="heap-куча" tabindex="-1">Heap (Куча) <a class="header-anchor" href="#heap-куча" aria-label="Permalink to &quot;Heap (Куча)&quot;">​</a></h1><h2 id="информация" tabindex="-1">Информация <a class="header-anchor" href="#информация" aria-label="Permalink to &quot;Информация&quot;">​</a></h2><div class="tip custom-block"><p class="custom-block-title">Куча</p><ul><li><strong>Куча</strong> - специализированная структура данных типа дерево, которая удовлетворяет свойству кучи: если B является узлом-потомком узла A, то ключ(A) ≥ ключ(B). Из этого следует, что элемент с наибольшим ключом всегда является корневым узлом кучи, поэтому иногда такие кучи называют max-кучами (в качестве альтернативы, если сравнение перевернуть, то наименьший элемент будет всегда корневым узлом, такие кучи называют min-кучами)</li><li><em>Реализация</em>: массив</li></ul></div><h2 id="операции" tabindex="-1">Операции <a class="header-anchor" href="#операции" aria-label="Permalink to &quot;Операции&quot;">​</a></h2><ul><li>Найти максимум или найти минимум: найти максимальный элемент в max-куче или минимальный элемент в min-куче, соответственно</li><li>Удалить максимум или удалить минимум: удалить корневой узел в max- или min-куче, соответственно</li><li>Увеличить ключ или уменьшить ключ: обновить ключ в max- или min-куче, соответственно</li><li>Добавить: добавление нового ключа в кучу</li><li>Слияние: соединение двух куч с целью создания новой кучи, содержащей все элементы обеих исходных</li></ul><h2 id="двоичная-куча" tabindex="-1">Двоичная куча <a class="header-anchor" href="#двоичная-куча" aria-label="Permalink to &quot;Двоичная куча&quot;">​</a></h2><img src="'+r+'" width="450px"><div class="tip custom-block"><p class="custom-block-title">Двоичная куча</p><ul><li><strong>Двоичная куча</strong> - ещё одна древовидная структура данных. В ней у каждого узла не более двух потомков. Также она является совершенным деревом: это значит, что в ней полностью заняты данными все уровни, а последний заполнен слева направо</li><li><em>Порядок уровней в двоичной куче важен</em>, в отличие от порядка узлов на одном и том же уровне. На иллюстрации видно, что в минимальной куче на третьем уровне значения идут не по порядку: 10, 6 и 12</li></ul></div><h3 id="разновидности" tabindex="-1">Разновидности <a class="header-anchor" href="#разновидности" aria-label="Permalink to &quot;Разновидности&quot;">​</a></h3><ul><li>Минимальная - ключ любого узла меньше ключей его потомков или равен им</li><li>Максимальная - ключ любого узла всегда больше ключей его потомков или равен им</li></ul><h2 id="сложность-алгоритма" tabindex="-1">Сложность алгоритма <a class="header-anchor" href="#сложность-алгоритма" aria-label="Permalink to &quot;Сложность алгоритма&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Алгоритм</th><th style="text-align:right;">Среднее значение</th><th style="text-align:right;">Худший случай</th></tr></thead><tbody><tr><td>Space</td><td style="text-align:right;">O(n)</td><td style="text-align:right;">O(n)</td></tr><tr><td>Search</td><td style="text-align:right;">O(n)</td><td style="text-align:right;">O(n)</td></tr><tr><td>Insert</td><td style="text-align:right;">O(1)</td><td style="text-align:right;">O(log n)</td></tr><tr><td>Delete</td><td style="text-align:right;">O(log n)</td><td style="text-align:right;">O(log n)</td></tr><tr><td>Peek</td><td style="text-align:right;">O(1)</td><td style="text-align:right;">O(1)</td></tr></tbody></table>',12)])])}const p=e(s,[["render",d]]);export{g as __pageData,p as default};
